() => {
  const [selectedMonth, setSelectedMonth] = React.useState(0);
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  // Exponential kernel with periodization
  const sigma = 0.3;
  const kernel = (d) => {
    const dd = Math.min(d, 12 - d);
    return Math.exp(-dd / (sigma * 6));
  };
  const cx = 190, cy = 160, r = 120;
  return React.createElement('div', { style: { display: 'flex', gap: 20, alignItems: 'flex-start' } },
    React.createElement('svg', { width: 380, height: 340, style: { background: '#1a1a2e', borderRadius: 12 } },
      // Circle
      React.createElement('circle', { cx, cy, r, fill: 'none', stroke: '#333', strokeWidth: 1 }),
      // Month nodes
      ...months.map((m, i) => {
        const angle = (i / 12) * 2 * Math.PI - Math.PI / 2;
        const x = cx + r * Math.cos(angle);
        const y = cy + r * Math.sin(angle);
        const dist = Math.min(Math.abs(i - selectedMonth), 12 - Math.abs(i - selectedMonth));
        const strength = kernel(Math.abs(i - selectedMonth));
        const isSelected = i === selectedMonth;
        return React.createElement('g', { key: i, onClick: () => setSelectedMonth(i), style: { cursor: 'pointer' } },
          // Connection line to selected
          !isSelected && React.createElement('line', {
            x1: cx + r * Math.cos((selectedMonth / 12) * 2 * Math.PI - Math.PI / 2),
            y1: cy + r * Math.sin((selectedMonth / 12) * 2 * Math.PI - Math.PI / 2),
            x2: x, y2: y,
            stroke: `rgba(99, 202, 255, ${strength * 0.7})`,
            strokeWidth: strength * 4
          }),
          React.createElement('circle', {
            cx: x, cy: y, r: isSelected ? 22 : 16,
            fill: isSelected ? '#4f8fea' : `rgba(79, 143, 234, ${0.2 + strength * 0.8})`,
            stroke: isSelected ? '#fff' : 'rgba(255,255,255,0.3)', strokeWidth: isSelected ? 2 : 1
          }),
          React.createElement('text', {
            x, y: y + 4, textAnchor: 'middle', fill: '#fff',
            fontSize: isSelected ? 11 : 9, fontWeight: isSelected ? 'bold' : 'normal'
          }, m)
        );
      }),
      React.createElement('text', { x: 190, y: 310, textAnchor: 'middle', fill: '#888', fontSize: 12 },
        'Click a month — line brightness = co-occurrence strength')
    ),
    // Kernel plot
    React.createElement('div', { style: { color: '#ccc', fontSize: 13, maxWidth: 200 } },
      React.createElement('div', { style: { fontWeight: 'bold', marginBottom: 8, color: '#4f8fea' } }, 'Co-occurrence Kernel'),
      React.createElement('p', { style: { fontSize: 12, lineHeight: 1.5 } },
        `Selected: ${months[selectedMonth]}. The brightness of each line shows C(Δ) = exp(−|Δ|/σ). Co-occurrence depends only on interval, not absolute month — that\'s translation symmetry.`
      ),
      React.createElement('div', { style: { marginTop: 12, fontSize: 11 } },
        ...months.map((m, i) => {
          const dist = Math.min(Math.abs(i - selectedMonth), 12 - Math.abs(i - selectedMonth));
          const s = kernel(Math.abs(i - selectedMonth));
          return React.createElement('div', { key: i, style: { display: 'flex', alignItems: 'center', gap: 6, marginBottom: 2 } },
            React.createElement('span', { style: { width: 30 } }, m),
            React.createElement('div', { style: { width: 80, height: 8, background: '#222', borderRadius: 4 } },
              React.createElement('div', { style: { width: `${s * 100}%`, height: '100%', background: '#4f8fea', borderRadius: 4 } })
            ),
            React.createElement('span', { style: { fontSize: 10, color: '#666' } }, `Δ=${dist}`)
          );
        })
      )
    )
  );
}

() => {
  const [numModes, setNumModes] = React.useState(1);
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const colors = ['#ff6b6b','#ff8e53','#ffd93d','#6bcb77','#4ecdc4','#45b7d1','#4f8fea','#7c6fff','#b567f0','#e056a0','#ff6b8a','#ff6b6b'];
  const sigma = 0.3;
  // Compute embedding coordinates for each month
  const embeddings = months.map((m, i) => {
    const x = i / 12;
    const coords = [];
    for (let n = 1; n <= numModes; n++) {
      const k = 2 * Math.PI * n;
      const amp = Math.sqrt(2 * sigma / (1 + sigma * sigma * k * k));
      coords.push(amp * Math.cos(k * x));
      coords.push(amp * Math.sin(k * x));
    }
    return coords;
  });
  // Project to 2D (first two components)
  const cx = 200, cy = 180;
  const scale = 280;
  const points = embeddings.map(e => ({
    x: cx + (e[0] || 0) * scale,
    y: cy + (e[1] || 0) * scale
  }));
  return React.createElement('div', null,
    React.createElement('div', { style: { display: 'flex', alignItems: 'center', gap: 16, marginBottom: 12 } },
      React.createElement('label', { style: { color: '#ccc', fontSize: 13 } }, `Fourier modes: ${numModes}`),
      React.createElement('input', {
        type: 'range', min: 1, max: 6, value: numModes,
        onChange: (e) => setNumModes(parseInt(e.target.value)),
        style: { width: 200 }
      }),
      React.createElement('span', { style: { color: '#888', fontSize: 11 } },
        numModes === 1 ? '→ Perfect circle (fundamental mode)' :
        numModes <= 3 ? '→ Circle with small perturbations' :
        '→ Higher harmonics add "ripples"'
      )
    ),
    React.createElement('svg', { width: 400, height: 360, style: { background: '#1a1a2e', borderRadius: 12 } },
      // Connect points in order
      ...points.map((p, i) => {
        const next = points[(i + 1) % 12];
        return React.createElement('line', {
          key: 'l' + i, x1: p.x, y1: p.y, x2: next.x, y2: next.y,
          stroke: 'rgba(99,202,255,0.3)', strokeWidth: 1
        });
      }),
      // Points
      ...points.map((p, i) => React.createElement('g', { key: i },
        React.createElement('circle', { cx: p.x, cy: p.y, r: 14, fill: colors[i], opacity: 0.9 }),
        React.createElement('text', {
          x: p.x, y: p.y + 4, textAnchor: 'middle', fill: '#fff', fontSize: 8, fontWeight: 'bold'
        }, months[i])
      )),
      React.createElement('text', { x: 200, y: 350, textAnchor: 'middle', fill: '#666', fontSize: 11 },
        'Projection onto first 2 PCA dimensions')
    )
  );
}

